"""Phase 5 human-play HTML renderer."""
from __future__ import annotations

import json
from html import escape

from characters import CHARACTERS
from .phrase_dict import EVENT_LABELS_KO, LANDING_TYPE_LABELS_KO


def render_play_html(
    session_id: str = "",
    seed: int = 0,
    human_seat: int = 0,
    human_seats: list[int] | tuple[int, ...] | set[int] | None = None,
    poll_interval_ms: int = 200,
) -> str:
    seats = list(sorted(set(int(seat) for seat in (human_seats or [human_seat]))))
    event_labels_json = json.dumps(EVENT_LABELS_KO, ensure_ascii=False, separators=(",", ":"))
    landing_type_labels_json = json.dumps(LANDING_TYPE_LABELS_KO, ensure_ascii=False, separators=(",", ":"))
    character_ability_json = json.dumps(
        {name: c.ability_text for name, c in CHARACTERS.items()},
        ensure_ascii=False,
        separators=(",", ":"),
    )
    html = _TEMPLATE
    html = html.replace("__SESSION_ID__", escape(session_id or "..."))
    html = html.replace("__SEED__", str(seed))
    html = html.replace("__HUMAN_SEAT__", str(human_seat))
    html = html.replace("__HUMAN_SEAT_LABEL__", escape(", ".join(f"P{seat + 1}" for seat in seats)))
    html = html.replace("__HUMAN_SEAT_JS__", str(human_seat + 1))
    html = html.replace("__HUMAN_SEATS_JS__", "[" + ",".join(str(seat + 1) for seat in seats) + "]")
    html = html.replace("__POLL_INTERVAL_MS__", str(poll_interval_ms))
    html = html.replace("__EVENT_LABELS_JSON__", event_labels_json)
    html = html.replace("__LANDING_TYPE_LABELS_JSON__", landing_type_labels_json)
    html = html.replace("__CHARACTER_ABILITY_JSON__", character_ability_json)
    return html


